const input = $('Workflow Input').first().json;
const { lead_id, business_name, niche, suburb, gbp_data } = input;

// Map niche to template category
const nicheCategoryMap = {
  'electrician': 'trades', 'plumber': 'trades', 'builder': 'trades',
  'painter': 'trades', 'landscaper': 'trades', 'hvac': 'trades',
  'physio': 'allied-health', 'chiro': 'allied-health', 'osteo': 'allied-health',
  'dentist': 'allied-health', 'gp': 'allied-health', 'optometrist': 'allied-health',
  'beauty': 'beauty-aesthetics', 'skin-clinic': 'beauty-aesthetics',
  'hair-salon': 'beauty-aesthetics', 'nail-salon': 'beauty-aesthetics',
  'personal-trainer': 'fitness-wellness', 'yoga': 'fitness-wellness',
  'pilates': 'fitness-wellness', 'gym': 'fitness-wellness',
  'accountant': 'professional-services', 'solicitor': 'professional-services',
  'mortgage-broker': 'professional-services', 'financial-planner': 'professional-services',
  'cafe': 'hospitality', 'restaurant': 'hospitality', 'food-truck': 'hospitality',
  'other': 'trades'
};
const category = nicheCategoryMap[niche] || 'trades';

// Serialise GBP data for the prompt
const gbpSummary = gbp_data ? JSON.stringify({
  name: gbp_data.name,
  address: gbp_data.full_address,
  phone: gbp_data.phone,
  website: gbp_data.site,
  description: gbp_data.description,
  rating: gbp_data.rating,
  reviews: gbp_data.reviews,
  subtypes: gbp_data.subtypes,
  photos: (gbp_data.photos || []).slice(0, 6),
  latitude: gbp_data.latitude,
  longitude: gbp_data.longitude
}, null, 2) : '{"name": "' + business_name + '", "address": "' + suburb + ', Australia"}';

const systemPrompt = `You are a specialist website content generator for Australian small service businesses.
You produce a structured JSON object called SiteProps that drives a ${category} website template.
The output must be valid JSON only — no commentary, no markdown fences.

SiteProps schema:
{
  "business": {
    "name": string,           // business name as it should appear on the site
    "phone": string,          // click-to-call format: "04XX XXX XXX"
    "email": string | null,
    "address": string,        // street address if available
    "suburb": string,
    "state": string,          // e.g. "NSW"
    "postcode": string | null,
    "abn": string | null,
    "tagline": string,        // compelling, specific to niche — max 12 words
    "description": string,    // 2-sentence business description, Australian English
    "yearFounded": number | null,
    "rating": number | null,
    "reviewCount": number | null
  },
  "brand": {
    "primaryColour": string,  // hex code matching niche — e.g. trades: "#1D4ED8"
    "accentColour": string,
    "fontStyle": "modern" | "classic" | "bold"
  },
  "services": [
    {
      "slug": string,         // kebab-case
      "name": string,
      "shortDescription": string,  // 1 sentence
      "longDescription": string,   // 3-4 sentences for service page
      "price": string | null,      // e.g. "From $120" or null if not typical to quote
      "icon": string               // lucide-react icon name e.g. "Wrench"
    }
  ],                               // 6–10 services
  "locations": [
    {
      "suburb": string,
      "state": string,
      "slug": string           // kebab-case
    }
  ],                               // primary suburb + 7–14 surrounding suburbs
  "serviceAreas": [
    {
      "slug": string,          // e.g. "plumber-auburn-nsw"
      "service": string,
      "suburb": string,
      "state": string,
      "headline": string,      // e.g. "Plumber in Auburn NSW — Same-Day Service"
      "body": string           // 2 sentences
    }
  ],                               // cross-product of top 3 services x top 5 locations
  "faq": [
    { "question": string, "answer": string }
  ],                               // 6–10 FAQs
  "photos": string[],              // GBP photo URLs, pass through
  "trustSignals": {
    "badges": string[],            // e.g. ["Licensed", "Insured", "10+ Years"]
    "guarantee": string | null     // e.g. "Same-day service or no call-out fee"
  },
  "meta": {
    "generatedAt": string,         // ISO timestamp
    "generatedBy": "claude-sonnet-4-5",
    "templateCategory": string,
    "niche": string,
    "schemaVersion": "1.0"
  }
}

Rules:
- All copy is Australian English (use -ise not -ize, "colour" not "color" etc.)
- Phone must be formatted as Australian mobile or landline
- Generate realistic suburb list based on the business suburb — nearby suburbs only
- Services must be specific to the niche, not generic
- The tagline must be specific and compelling, never generic like "Quality Service You Can Trust"
- Do not invent contact details not present in GBP data; use null for missing fields
- Output valid JSON only — the system will crash if you add any prose`;

const userMessage = `Business niche: ${niche}
Primary suburb: ${suburb}
Template category: ${category}

Google Business Profile data:
${gbpSummary}

Generate SiteProps JSON now.`;

return [{
  json: {
    lead_id,
    business_name,
    niche,
    suburb,
    category,
    system_prompt: systemPrompt,
    user_message: userMessage,
    generation_start: Date.now()
  }
}];

const prevInput = $('Build Claude Prompt').first().json;
const raw = $input.first().json;

const generationMs = Date.now() - prevInput.generation_start;

// Extract text from Claude response
const textContent = raw.content && raw.content[0] && raw.content[0].text;
if (!textContent) {
  throw new Error('Claude returned empty content. Stop reason: ' + raw.stop_reason);
}

// Strip potential markdown fences
const cleaned = textContent.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let siteProps;
try {
  siteProps = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude response is not valid JSON: ' + e.message + '\n\nRaw: ' + textContent.substring(0, 500));
}

// Validate required fields
const required = [
  ['business', 'object'],
  ['business.name', 'string'],
  ['services', 'array'],
  ['locations', 'array'],
  ['faq', 'array']
];

function getPath(obj, path) {
  return path.split('.').reduce((o, k) => (o ? o[k] : undefined), obj);
}

for (const [path, type] of required) {
  const val = getPath(siteProps, path);
  if (val === undefined || val === null) throw new Error('SiteProps missing required field: ' + path);
  if (type === 'array' && !Array.isArray(val)) throw new Error('SiteProps field ' + path + ' must be array');
  if (type === 'string' && typeof val !== 'string') throw new Error('SiteProps field ' + path + ' must be string');
}

if (!siteProps.services || siteProps.services.length < 3) {
  throw new Error('SiteProps must have at least 3 services, got: ' + (siteProps.services || []).length);
}

if (!siteProps.locations || siteProps.locations.length < 3) {
  throw new Error('SiteProps must have at least 3 locations, got: ' + (siteProps.locations || []).length);
}

// Inject meta if missing
if (!siteProps.meta) {
  siteProps.meta = {};
}
siteProps.meta.generatedAt = new Date().toISOString();
siteProps.meta.generatedBy = 'claude-sonnet-4-5';
siteProps.meta.niche = prevInput.niche;
siteProps.meta.templateCategory = prevInput.category;
siteProps.meta.schemaVersion = '1.0';

// Generate slug from business name + suburb
const slugBase = (siteProps.business.name + '-' + prevInput.suburb)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 60);

return [{
  json: {
    lead_id: prevInput.lead_id,
    niche: prevInput.niche,
    category: prevInput.category,
    slug: slugBase,
    site_props: siteProps,
    generation_ms: generationMs
  }
}];
